import React, { useState, useEffect } from "react";
import { Layers, Hash, Save, CheckSquare, Square, Loader2, Edit, Trash2, RefreshCw, Search } from "lucide-react";
import axios from "../api/axios";
import toast from "react-hot-toast";

const CategoryMaster = () => {
  const [exams, setExams] = useState([]);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [editId, setEditId] = useState(null);
  const [searchTerm, setSearchTerm] = useState("");
  
  const [formData, setFormData] = useState({ catId: "", examId: "", catName: "", features: [] });
  const options = ["SYLLABUS", "MOCK TEST", "PYQ", "STUDY MATERIAL", "VIDEOS"];

  const fetchData = async () => {
    setLoading(true);
    try {
      const [exRes, catRes, idRes] = await Promise.all([
        axios.get("/master/exam/all"),
        axios.get("/master/category/all"),
        axios.get("/master/category/next-id")
      ]);
      setExams(exRes.data.data);
      setCategories(catRes.data.data);
      if (!editId) setFormData(prev => ({ ...prev, catId: idRes.data.nextId }));
    } catch (err) {
      toast.error("DATA SYNC FAILED");
    } finally { setLoading(false); }
  };

  useEffect(() => { fetchData(); }, []);

  const handleEdit = (cat) => {
    setEditId(cat._id);
    setFormData({
      catId: cat.catId,
      examId: cat.examId._id,
      catName: cat.catName,
      features: cat.features
    });
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleDelete = async (id) => {
    if (!window.confirm("DELETE THIS CATEGORY?")) return;
    try {
      await axios.delete(`/master/category/${id}`);
      toast.success("DELETED");
      fetchData();
    } catch { toast.error("DELETE FAILED"); }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsSaving(true);
    try {
      const url = editId ? `/master/category/update/${editId}` : "/master/category/add";
      const method = editId ? "put" : "post";
      const res = await axios[method](url, formData);
      if (res.data.success) {
        toast.success(editId ? "UPDATED" : "SAVED");
        setEditId(null);
        setFormData({ catId: "", examId: "", catName: "", features: [] });
        fetchData();
      }
    } catch { toast.error("OPERATION FAILED"); }
    finally { setIsSaving(false); }
  };

  const filteredCategories = categories.filter(c => 
    c.catName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    c.examId?.examName.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="p-6 max-w-6xl mx-auto space-y-10">
      {/* FORM SECTION */}
      <form onSubmit={handleSubmit} className="bg-white rounded-[32px] p-8 shadow-xl border border-slate-100 transition-all">
        <h1 className="text-2xl font-black mb-8 uppercase tracking-tighter flex items-center justify-between">
          <div className="flex items-center gap-3">
            <Layers className="text-blue-600" /> {editId ? "Update Category" : "Category Master"}
          </div>
          {editId && <button onClick={() => {setEditId(null); fetchData();}} className="text-xs text-red-500 underline">Cancel Edit</button>}
        </h1>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
          <div>
            <label className="text-[10px] font-black uppercase text-slate-400 block mb-2">Category ID</label>
            <div className="p-4 bg-slate-50 rounded-2xl font-bold text-blue-600 border border-slate-100 flex items-center gap-2">
              <Hash size={14} /> {formData.catId}
            </div>
          </div>
          <div>
            <label className="text-[10px] font-black uppercase text-slate-400 block mb-2">Select Parent Exam</label>
            <select className="w-full p-4 border-2 border-slate-100 rounded-2xl font-bold outline-none focus:border-blue-600"
              value={formData.examId} onChange={(e) => setFormData({...formData, examId: e.target.value})} required>
              <option value="">-- CHOOSE --</option>
              {exams.map(ex => <option key={ex._id} value={ex._id}>{ex.examName}</option>)}
            </select>
          </div>
          <div>
            <label className="text-[10px] font-black uppercase text-slate-400 block mb-2">Sub-Exam Name</label>
            <input type="text" required className="w-full p-4 border-2 border-slate-100 rounded-2xl font-bold outline-none focus:border-blue-600 uppercase"
              value={formData.catName} onChange={(e) => setFormData({...formData, catName: e.target.value.toUpperCase()})} placeholder="NTPC, CGL..." />
          </div>
        </div>

        <div className="mb-8 p-6 bg-slate-50 rounded-2xl">
          <label className="text-[10px] font-black uppercase text-slate-400 block mb-4">Content Features (Enable/Disable)</label>
          <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
            {options.map(opt => (
              <button key={opt} type="button" onClick={() => setFormData(prev => ({
                ...prev, features: prev.features.includes(opt) ? prev.features.filter(i => i !== opt) : [...prev.features, opt]
              }))} className={`flex items-center gap-2 p-3 rounded-xl border-2 transition-all font-black text-[9px] ${
                formData.features.includes(opt) ? "bg-blue-600 border-blue-600 text-white shadow-lg shadow-blue-200" : "bg-white border-slate-100 text-slate-400"
              }`}>
                {formData.features.includes(opt) ? <CheckSquare size={14}/> : <Square size={14}/>} {opt}
              </button>
            ))}
          </div>
        </div>

        <button disabled={isSaving} className="w-full py-4 bg-[#0F172A] text-white rounded-2xl font-black uppercase tracking-widest hover:bg-blue-600 transition-all flex justify-center items-center gap-2">
          {isSaving ? <Loader2 className="animate-spin" /> : <Save size={20} />} {editId ? "Update Category" : "Save Category"}
        </button>
      </form>

      {/* TABLE SECTION */}
      <div className="bg-white rounded-[32px] shadow-xl border border-slate-100 overflow-hidden">
        <div className="p-6 border-b border-slate-50 flex flex-col md:flex-row justify-between items-center gap-4">
          <h2 className="font-black uppercase tracking-tighter text-slate-800">Existing Categories</h2>
          <div className="relative w-full md:w-72">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
            <input type="text" placeholder="Search..." className="w-full pl-10 pr-4 py-2 bg-slate-50 rounded-xl text-xs font-bold outline-none" onChange={(e) => setSearchTerm(e.target.value)} />
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-900 text-white text-[10px] font-black uppercase tracking-widest">
                <th className="p-4">ID</th>
                <th className="p-4">Exam</th>
                <th className="p-4">Category</th>
                <th className="p-4">Features</th>
                <th className="p-4 text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredCategories.map(cat => (
                <tr key={cat._id} className="text-xs font-bold text-slate-600 hover:bg-slate-50/50 transition-all">
                  <td className="p-4 text-blue-600">{cat.catId}</td>
                  <td className="p-4 uppercase">{cat.examId?.examName}</td>
                  <td className="p-4 uppercase text-slate-900">{cat.catName}</td>
                  <td className="p-4">
                    <div className="flex flex-wrap gap-1">
                      {cat.features.map(f => <span key={f} className="px-2 py-0.5 bg-sky-100 text-sky-600 rounded text-[8px]">{f}</span>)}
                    </div>
                  </td>
                  <td className="p-4 flex justify-center gap-2">
                    <button onClick={() => handleEdit(cat)} className="p-2 bg-blue-50 text-blue-600 rounded-lg hover:bg-blue-600 hover:text-white transition-all"><Edit size={14}/></button>
                    <button onClick={() => handleDelete(cat._id)} className="p-2 bg-red-50 text-red-500 rounded-lg hover:bg-red-500 hover:text-white transition-all"><Trash2 size={14}/></button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default CategoryMaster;
